import re
from typing import List, Dict, Any, Tuple
from pathlib import Path

def parse_strace_log(log_path: str) -> Dict[str, Any]:
    """
    Parses a strace log generated by the sandbox.
    Extracts PIDs, syscall processes, file accesses, and network attempts.
    """
    # strace regex basic format: [pid] syscall(args) = return
    line_pattern = re.compile(r'^(\d+)\s+([a-zA-Z0-9_]+)\((.*)$')

    processes = {}  # pid -> { pid, command, children: [], network: [], files: [], syscall_counts: {} }
    parent_map = {} # child_pid -> parent_pid
    syscalls_executed = []
    suspicious_flags = []
    
    if not Path(log_path).exists():
        return {"processes": {}, "parent_map": {}, "events": [], "flags": []}

    with open(log_path, 'r', encoding='utf-8', errors='ignore') as f:
        for line in f:
            match = line_pattern.match(line.strip())
            if not match:
                continue
                
            pid = match.group(1)
            syscall = match.group(2)
            args_raw = match.group(3)

            if pid not in processes:
                processes[pid] = {
                    "pid": pid,
                    "command": "unknown",
                    "children": [],
                    "network": [],
                    "files": [],
                    "syscall_counts": {}
                }

            proc = processes[pid]
            proc["syscall_counts"][syscall] = proc["syscall_counts"].get(syscall, 0) + 1

            if syscall in ("clone", "fork", "vfork"):
                res_match = re.search(r'=\s+(\d+)$', args_raw)
                if res_match:
                    child_pid = res_match.group(1)
                    parent_map[child_pid] = pid
                    proc["children"].append(child_pid)

            elif syscall == "execve":
                binary_match = re.match(r'^"([^"]+)"', args_raw)
                if binary_match:
                    target_bin = binary_match.group(1)
                    proc["command"] = target_bin.split('/')[-1]
                    syscalls_executed.append({
                        "pid": pid, "type": "execve", "target": target_bin
                    })
                    if target_bin not in ("/usr/local/bin/pip", "/usr/bin/python", "/usr/bin/python3"): 
                        suspicious_flags.append(f"Process {pid} spawned external binary {target_bin}")

            elif syscall == "connect":
                ip_match = re.search(r'sin_addr=inet_addr\("([^"]+)"\)', args_raw)
                port_match = re.search(r'sin_port=htons\(([0-9]+)\)', args_raw)
                if ip_match:
                    ip = ip_match.group(1)
                    port = port_match.group(1) if port_match else "unknown"
                    target = f"{ip}:{port}"
                    proc["network"].append(target)
                    syscalls_executed.append({"pid": pid, "type": "connect", "target": target})
                    suspicious_flags.append(f"Network connection attempt to {target}")

            elif syscall == "openat":
                file_match = re.search(r',"([^"]+)"', args_raw)
                if file_match:
                    filepath = file_match.group(1)
                    proc["files"].append(filepath)
                    syscalls_executed.append({"pid": pid, "type": "openat", "target": filepath})
                    if "/etc/passwd" in filepath or ".ssh" in filepath or "/shadow" in filepath:
                        suspicious_flags.append(f"Suspicious sensitive file access: {filepath}")
                    
            elif syscall in ("sendto", "socket"):
                if "AF_INET" in args_raw:
                    proc["network"].append("AF_INET_SOCKET")
                    suspicious_flags.append(f"Raw socket or sendto (AF_INET) detected in PID {pid}")
                    syscalls_executed.append({"pid": pid, "type": syscall, "target": "AF_INET"})

    return {
        "processes": processes,
        "parent_map": parent_map,
        "events": syscalls_executed,
        "flags": list(set(suspicious_flags))
    }
